                                                         element,
                                                         ETGChargeCodes_DS,
                                                         fieldNum(ETG_ChargeCodes,ETG_Estimation)
                                                        );
        numberSeqFormHandler = NumberSeqFormHandler::newForm(SalesParameters::numReEstimstion().NumberSequenceId,
                                                         element,
                                                         ETGChargeCodes_DS,
                                                         fieldNum(ETG_ChargeCodes,ETG_Estimation)
                                                        );

