/// <summary>
///
/// </summary>
/// <returns></returns>
public int active()
{
    int ret;
    boolean                 editOrder = true;

    ret = super();
    if(ETGChargeCodes.Estimation == NoYes::Yes)
    {
        Estimation.enabled(false);
    }
    if(ETGChargeCodes.Estimation == NoYes::No)
    {
        Estimation.enabled(true);
    }
    if(ETGACFParameters::find().EnableProvisionalCharges == NoYes::Yes)
    {
        if(ETGChargeCodes.IncoTerms)
        {
            ETGChargeCodes_ds.allowCreate(false);
            ETGChargeCodes_ds.allowDelete(false);
            ETGChargeCodes_ds.object(fieldNum(ETG_ChargeCodes, Qty)).allowEdit(false);
            ETGChargeCodes_ds.object(fieldNum(ETG_ChargeCodes, Value)).allowEdit(true);
            ETGChargeCodes_ds.object(fieldNum(ETG_ChargeCodes, ETG_MarkupCategory)).allowEdit(true);
        }
    }
    return ret;
}

/// <summary>
/// it will return True if Agreement having confirmations
/// </summary>
public boolean isAgreementHavingConfirmations(RefRecId  _AgreementHeader)
{
    boolean                 isAgreementHavingConfirmations;
    AgreementHeaderHistory  agreementHeaderHistory;

    select firstonly agreementHeaderHistory
        where agreementHeaderHistory.AgreementHeader == _AgreementHeader;

    isAgreementHavingConfirmations  = agreementHeaderHistory.RecId != 0;

    return  isAgreementHavingConfirmations;
}

/// <summary>
///
/// </summary>
public void init()
{
    boolean                 editOrder = true;
    SalesAgreementHeader    salesAgreementHeader,salesAgreementHeaderLoc;
    PurchAgreementHeader    purchAgreementHeader,purchAgreementHeaderLoc;
    AgreementLine           agreementLine;
    AgreementLineQuantityCommitment agreementLineQuantityCommitment;

    ETGCanadaParameters                 canadaParameters    = ETGCanadaParameters::find();

    super();

    if (element.args() && element.args().dataset() == tableNum(SalesAgreementHeader))
    {
        salesAgreementHeader = element.args().record();

        select salesAgreementHeaderLoc where salesAgreementHeaderLoc.SalesNumberSequence == salesAgreementHeader.SalesNumberSequence;
        if(salesAgreementHeaderLoc)
        {
            select agreementLine where agreementLine.Agreement == salesAgreementHeaderLoc.RecId;
        }
        select agreementLineQuantityCommitment where
        agreementLineQuantityCommitment.RecId == agreementLine.RecId;

        //NS, DLT ,11032025, Provisional charges IncoTerms
        if(ETGACFParameters::find().EnableProvisionalCharges && 
            AgreementClassification::find(salesAgreementHeaderLoc.AgreementClassification).ETGIncoTerms == NoYes::Yes)
        {
            if(!salesAgreementHeaderLoc.agreementHeaderDefault().DeliveryTerm)
            {
                throw error(strFmt("Terms of delivery is mandatory for agreement %1", salesAgreementHeaderLoc.SalesNumberSequence));
            }
            ETGProvisionalChargesCreate::createChargesSales(salesAgreementHeaderLoc);
        }
        //NE, DLT ,11032025, Provisional charges IncoTerms

        while select forupdate eTGChargeCodes 
        where eTGChargeCodes.PurchNumberSequence == salesAgreementHeaderLoc.SalesNumberSequence
        {
            if(eTGChargeCodes.Qty != agreementLineQuantityCommitment.CommitedQuantity)
            {
                ttsbegin;

                //NS, DLT ,11032025, Provisional charges IncoTerms
                if(ETGACFParameters::find().EnableProvisionalCharges &&
                    AgreementClassification::find(salesAgreementHeaderLoc.AgreementClassification).ETGIncoTerms == NoYes::Yes)
                {
                    AgreementLineQuantityCommitment agreementLineQuantityCommitmentETG;
                    select sum(CommitedQuantity) from agreementLineQuantityCommitmentETG
                        where agreementLineQuantityCommitmentETG.Agreement == salesAgreementHeaderLoc.RecId;

                    eTGChargeCodes.Qty = agreementLineQuantityCommitmentETG.CommitedQuantity;
                    eTGChargeCodes.CurrencyCode = salesAgreementHeader.Currency;
                }
                else
                {
                    eTGChargeCodes.Qty = agreementLineQuantityCommitment.CommitedQuantity;
                    eTGChargeCodes.CurrencyCode = agreementLineQuantityCommitment.Currency;
                }
                //NE, DLT ,11032025, Provisional charges IncoTerms


                if(eTGChargeCodes.ETG_MarkupCategory == ETG_MarkupCategory::Pcs)
                {
                    eTGChargeCodes.AmountMST                  = eTGChargeCodes.Value * eTGChargeCodes.Qty;
                    eTGChargeCodes.Amountinaccountingcurrency = eTGChargeCodes.ExchangeRate * eTGChargeCodes.AmountMST;
                    eTGChargeCodes.Amountinreportingcurrency  = eTGChargeCodes.ReportingExchangeRate * eTGChargeCodes.AmountMST;

                }
                else if(eTGChargeCodes.ETG_MarkupCategory == ETG_MarkupCategory::Fixed)
                {
                    eTGChargeCodes.AmountMST                  = eTGChargeCodes.Value;
                    eTGChargeCodes.Amountinaccountingcurrency = eTGChargeCodes.ExchangeRate * eTGChargeCodes.AmountMST;
                    eTGChargeCodes.Amountinreportingcurrency  = eTGChargeCodes.ReportingExchangeRate * eTGChargeCodes.AmountMST;
                }
                else if(eTGChargeCodes.ETG_MarkupCategory == ETG_MarkupCategory::Percentage)
                {
                    eTGChargeCodes.AmountMST                  = ((agreementLineQuantityCommitment.CommitedQuantity * agreementLineQuantityCommitment.PricePerUnit) -(((agreementLineQuantityCommitment.LineDiscountPercent) * (agreementLineQuantityCommitment.CommitedQuantity * agreementLineQuantityCommitment.PricePerUnit))/100)) *(eTGChargeCodes.Value/100);
                    eTGChargeCodes.Amountinaccountingcurrency = eTGChargeCodes.ExchangeRate * eTGChargeCodes.AmountMST;
                    eTGChargeCodes.Amountinreportingcurrency  = eTGChargeCodes.ReportingExchangeRate * eTGChargeCodes.AmountMST;
                }

                eTGChargeCodes.update();
                ttscommit;
            }
            }

        editOrder   = !this.isAgreementHavingConfirmations(salesAgreementHeader.RecId);
        //CS DLT ValuePerPiece by Rajat Dubey 10/06/2025
        if(ETGACFParameters::find().EnableProvisionalCharges == NoYes::Yes && ETGChargeCodes.IncoTerms && salesAgreementHeader.AgreementState == AgreementState::OnHold)
        {
            ETGChargeCodes_ds.allowCreate(false);
            ETGChargeCodes_ds.allowDelete(false);
            ETGChargeCodes_ds.object(fieldNum(ETG_ChargeCodes, Qty)).allowEdit(false);
            ETGChargeCodes_ds.object(fieldNum(ETG_ChargeCodes, Value)).allowEdit(true);
            ETGChargeCodes_ds.object(fieldNum(ETG_ChargeCodes, ETG_MarkupCategory)).allowEdit(true);
            ETGChargeCodes_ds.object(fieldNum(ETG_ChargeCodes, ValuePerPiece)).allowEdit(true);
        }
        else
        {
            ETGChargeCodes_DS.allowEdit(editOrder);
            ETGChargeCodes_DS.allowCreate(editOrder);
            ETGChargeCodes_DS.allowDelete(editOrder);
        }
        //CE DLT ValuePerPiece by Rajat Dubey 10/06/2025
    }

    if (element.args() && element.args().dataset() == tableNum(PurchAgreementHeader))
    {
        purchAgreementHeader = element.args().record();

        select purchAgreementHeaderLoc where purchAgreementHeaderLoc.PurchNumberSequence == purchAgreementHeader.PurchNumberSequence;
        if(purchAgreementHeaderLoc)
        {
            select agreementLine where agreementLine.Agreement == purchAgreementHeaderLoc.RecId;
        }
        select agreementLineQuantityCommitment where
        agreementLineQuantityCommitment.RecId == agreementLine.RecId;

        //NS, DLT ,11032025, Provisional charges IncoTerms
        if(ETGACFParameters::find().EnableProvisionalCharges && 
            AgreementClassification::find(purchAgreementHeader.AgreementClassification).ETGIncoTerms == NoYes::Yes)
        {
            if(!purchAgreementHeader.agreementHeaderDefault().DeliveryTerm)
            {
                throw error(strFmt("Terms of delivery is mandatory for agreement %1", purchAgreementHeader.PurchNumberSequence));
            }
            ETGProvisionalChargesCreate::createChargesPurch(purchAgreementHeader);
        }
        //NE, DLT ,11032025, Provisional charges IncoTerms


        while select forupdate eTGChargeCodes 
            where eTGChargeCodes.PurchNumberSequence == purchAgreementHeader.PurchNumberSequence
        {
            ttsbegin;
            if(eTGChargeCodes.Qty != agreementLineQuantityCommitment.CommitedQuantity)
            {
                //NS, DLT ,11032025, Provisional charges IncoTerms
                if(ETGACFParameters::find().EnableProvisionalCharges &&
                    AgreementClassification::find(purchAgreementHeader.AgreementClassification).ETGIncoTerms == NoYes::Yes)
                {
                    AgreementLineQuantityCommitment agreementLineQuantityCommitmentETG;
                    select sum(CommitedQuantity) from agreementLineQuantityCommitmentETG
                        where agreementLineQuantityCommitmentETG.Agreement == purchAgreementHeader.RecId;

                    eTGChargeCodes.Qty = agreementLineQuantityCommitmentETG.CommitedQuantity;
                    eTGChargeCodes.CurrencyCode = purchAgreementHeader.Currency;
                }
                else
                {
                    eTGChargeCodes.Qty = agreementLineQuantityCommitment.CommitedQuantity;
                    eTGChargeCodes.CurrencyCode = agreementLineQuantityCommitment.Currency;
                }
                //NE, DLT ,11032025, Provisional charges IncoTerms


                if(eTGChargeCodes.ETG_MarkupCategory == ETG_MarkupCategory::Pcs)
                {
                    eTGChargeCodes.AmountMST                  = eTGChargeCodes.Value * eTGChargeCodes.Qty;
                    eTGChargeCodes.Amountinaccountingcurrency = eTGChargeCodes.ExchangeRate * eTGChargeCodes.AmountMST;
                    eTGChargeCodes.Amountinreportingcurrency  = eTGChargeCodes.ReportingExchangeRate * eTGChargeCodes.AmountMST;

                }
                else if(eTGChargeCodes.ETG_MarkupCategory == ETG_MarkupCategory::Fixed)
                {
                    eTGChargeCodes.AmountMST                  = eTGChargeCodes.Value;
                    eTGChargeCodes.Amountinaccountingcurrency = eTGChargeCodes.ExchangeRate * eTGChargeCodes.AmountMST;
                    eTGChargeCodes.Amountinreportingcurrency  = eTGChargeCodes.ReportingExchangeRate * eTGChargeCodes.AmountMST;
                }
                else if(eTGChargeCodes.ETG_MarkupCategory == ETG_MarkupCategory::Percentage)
                {
                    eTGChargeCodes.AmountMST                  = ((agreementLineQuantityCommitment.CommitedQuantity * agreementLineQuantityCommitment.PricePerUnit) -(((agreementLineQuantityCommitment.LineDiscountPercent) * (agreementLineQuantityCommitment.CommitedQuantity * agreementLineQuantityCommitment.PricePerUnit))/100)) *(eTGChargeCodes.Value/100);
                    eTGChargeCodes.Amountinaccountingcurrency = eTGChargeCodes.ExchangeRate * eTGChargeCodes.AmountMST;
                    eTGChargeCodes.Amountinreportingcurrency  = eTGChargeCodes.ReportingExchangeRate * eTGChargeCodes.AmountMST;
                }
            }
            eTGChargeCodes.update();
            ttscommit;
        }

        editOrder   = !this.isAgreementHavingConfirmations(purchAgreementHeader.RecId);
        //CS DLT ValuePerPiece by Rajat Dubey 10/06/2025
        if(ETGACFParameters::find().EnableProvisionalCharges == NoYes::Yes && ETGChargeCodes.IncoTerms && purchAgreementHeader.AgreementState == AgreementState::OnHold)
        {
            ETGChargeCodes_ds.allowCreate(false);
            ETGChargeCodes_ds.allowDelete(false);
            ETGChargeCodes_ds.object(fieldNum(ETG_ChargeCodes, Qty)).allowEdit(false);
            ETGChargeCodes_ds.object(fieldNum(ETG_ChargeCodes, Value)).allowEdit(true);
            ETGChargeCodes_ds.object(fieldNum(ETG_ChargeCodes, ETG_MarkupCategory)).allowEdit(true);
            ETGChargeCodes_ds.object(fieldNum(ETG_ChargeCodes, ValuePerPiece)).allowEdit(true);
        }
        else
        {
            ETGChargeCodes_DS.allowEdit(editOrder);
            ETGChargeCodes_DS.allowCreate(editOrder);
            ETGChargeCodes_DS.allowDelete(editOrder);
        }
        //CE DLT ValuePerPiece by Rajat Dubey 10/06/2025
    }
    //Freeze the charges when data is from DMS 
    if (salesAgreementHeader.RecId && salesAgreementHeader.ETGDMSDealNumber)
    {
        if (canadaParameters.FreezDMSCharges)
        {
            ETGChargeCodes_DS.allowEdit(false);
            ETGChargeCodes_DS.allowCreate(false);
            ETGChargeCodes_DS.allowDelete(false);
        }
        else
        {
            ETGChargeCodes_DS.allowEdit(true);
            ETGChargeCodes_DS.allowCreate(true);
            ETGChargeCodes_DS.allowDelete(true);
        }
    }

}

/// <summary>
///
/// </summary>
