public int active()
{
    int ret;

    ret = super();
    if(ETG_Chargecodelines.Estimation == NoYes::Yes)
    {
        EstimationLines.enabled(false);
    }
    if(ETG_Chargecodelines.Estimation == NoYes::No)
    {
        EstimationLines.enabled(true);
    }
    return ret;
}

/// <summary>
///
/// </summary>
public void clicked()
{
    Args                            args;
    Object                          formRun;

    ETGCreateJournalHelper  eTGCreateJournalHelper = new ETGCreateJournalHelper();
    eTGCreateJournalHelper.inserActualtLines(ETG_Chargecodelines.ETGLineestimationno);

    super();

    // open form

    args = new Args();
    args.record(ETG_Chargecodelines);
    args.name(formstr(ETG_ActualAgreement));
    formRun = classfactory.formRunClass(args);
    formRun.init();
    formRun.run();
    formRun.wait();
}
